#[test]
fn boost_updates_attention_without_reviving_incident_evidence() {
    // Regression: focusing an artifact revived old failures and modifications;
    // node-only attention must leave every incident edge's decay clock intact.
    let s = store();
    add_node(&s, "a", NodeType::Artifact, "a", NOW - HOUR);
    add_node(&s, "b", NodeType::Artifact, "b", NOW);
    s.upsert_edge(&raw_edge(
        "a",
        "b",
        RelationType::Modified,
        1.0,
        1.0,
        NOW - 10 * HOUR,
    ))
    .unwrap();

    let before = s
        .traverse(&["a".into()], Direction::Outgoing, 1, 0.05, NOW)
        .unwrap();
    assert!(!before.nodes.iter().any(|n| n.node.id == "b"));

    assert!(s.boost("a", NOW).unwrap());
    assert!(!s.boost("missing", NOW).unwrap());

    let after = s
        .traverse(&["a".into()], Direction::Outgoing, 1, 0.05, NOW)
        .unwrap();
    assert!(!after.nodes.iter().any(|n| n.node.id == "b"));
    assert_eq!(s.get_node("a").unwrap().unwrap().last_accessed_at, NOW);
}

